import datetime
from zoneinfo import ZoneInfo

def mock_appointments_for_future(next_n_days = 25):
    '''
    Generates mock appointments in the future of now
    eg.
    [
        "2026-03-02T09:00:00",  # Monday Mar 2, 2026 09:00 AM
        "2026-03-02T10:30:00",  # Monday Mar 2, 2026 10:30 AM
        "2026-03-02T13:00:00",  # Monday Mar 2, 2026 01:00 PM
        "2026-03-02T15:30:00",  # Monday Mar 2, 2026 03:30 PM
    ]
    '''
    tz = ZoneInfo("America/Los_Angeles")
    mock_appointments = []
    for day in range(1, next_n_days + 1):
        tomorrow = (datetime.datetime.now(tz).date() + datetime.timedelta(days=day))
        times = [datetime.time(9, 0), datetime.time(10, 30), datetime.time(13, 0), datetime.time(15, 30)]
        mock_appointments.extend([
            datetime.datetime.combine(tomorrow, t, tzinfo=tz).replace(microsecond=0).isoformat()
            for t in times
        ])
    return mock_appointments

MOCK_APPOINTMENTS = mock_appointments_for_future()
